+fn check_message<'a>(report: &'a Value, code: &str) -> &'a str {
+    report["checks"]
+        .as_array()
+        .expect("checks array")
+        .iter()
+        .find(|entry| entry["code"].as_str() == Some(code))
+        .and_then(|entry| entry["message"].as_str())
+        .unwrap_or_else(|| panic!("missing doctor check message {code}"))
